const result = $input.first().json;

if (!result.id_paciente) {
  return [{ json: { resultado: 'Paciente não encontrado no cadastro. Pode ser um novo paciente.' } }];
}

let resultado = `Paciente encontrado:\n`;
resultado += `👤 ${result.nome}\n`;
resultado += `📱 ${result.telefone}\n`;
if (result.data_nascimento) resultado += `🎂 ${new Date(result.data_nascimento).toLocaleDateString('pt-BR')}\n`;
if (result.convenio) resultado += `🏥 Convênio: ${result.convenio}\n`;
if (result.alergias && result.alergias.length > 0) resultado += `⚠️ Alergias: ${result.alergias.join(', ')}\n`;
if (result.condicoes_medicas && result.condicoes_medicas.length > 0) resultado += `🩺 Condições: ${result.condicoes_medicas.join(', ')}\n`;
resultado += `📊 Total de consultas: ${result.total_agendamentos || 0}\n`;
if ((result.tratamentos_ativos || 0) > 0) resultado += `🔄 Tratamentos ativos: ${result.tratamentos_ativos}\n`;
if (result.ultima_consulta) resultado += `📅 Última consulta: ${new Date(result.ultima_consulta).toLocaleDateString('pt-BR')}\n`;

return [{ json: { resultado, patient_id: result.id_paciente } }];
